import{_ as a,H as r,f as e,i as l}from"./chunks/framework.eFU6Tutu.js";const p=JSON.parse('{"title":"Лук (зелёный)","description":"","frontmatter":{},"headers":[],"relativePath":"plants/chives.md","filePath":"plants/chives.md"}'),i={name:"plants/chives.md"};function d(o,t,h,n,s,c){return r(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="лук-зеленыи" tabindex="-1">Лук (зелёный) <a class="header-anchor" href="#лук-зеленыи" aria-label="Permalink to &quot;Лук (зелёный)&quot;">​</a></h1><p>Зелёный лук — одна из самых простых культур для выращивания на подоконнике. Даже в стакане воды луковица даёт свежую зелень всего за 7–10 дней. Перья богаты витаминами и придают блюдам свежий, слегка острый вкус.</p><h2 id="описание" tabindex="-1">Описание <a class="header-anchor" href="#описание" aria-label="Permalink to &quot;Описание&quot;">​</a></h2><p>Зелёный лук — это молодые побеги лука-репки, лука-шалота или других многолетних луков (батун, слизун). Перья полые внутри, тёмно-зелёного цвета, с белёсым основанием. Высота — 15–40 см в зависимости от сорта и условий. Растение многолетнее, но на подоконнике его обычно выращивают заново из луковицы или семян.</p><h2 id="популярные-способы-выращивания" tabindex="-1">Популярные способы выращивания <a class="header-anchor" href="#популярные-способы-выращивания" aria-label="Permalink to &quot;Популярные способы выращивания&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Способ</th><th>Особенности</th></tr></thead><tbody><tr><td><strong>Из луковицы (репки)</strong></td><td>Самый быстрый — урожай через 7–10 дней. Луковицу помещают в воду или сажают в грунт</td></tr><tr><td><strong>Из севка (мелкие луковицы)</strong></td><td>Дают более нежные перья, чем крупные луковицы</td></tr><tr><td><strong>Из семян (чернушки)</strong></td><td>Дольше (перо готово через 2–3 месяца), но зелень отрастает несколько раз</td></tr><tr><td><strong>Многолетние луки (батун, шнитт)</strong></td><td>Растут на одном месте до 3–4 лет, зелень срезают несколько раз за сезон</td></tr></tbody></table><h2 id="уход" tabindex="-1">Уход <a class="header-anchor" href="#уход" aria-label="Permalink to &quot;Уход&quot;">​</a></h2><p>Зелёный лук — одна из самых простых культур для подоконника, но общие принципы ухода схожи с другой зеленью. Подробнее читайте в <a href="/care/greens/#лук">гайде по уходу за зеленью</a>.</p><h2 id="проблемы-при-выращивании" tabindex="-1">Проблемы при выращивании <a class="header-anchor" href="#проблемы-при-выращивании" aria-label="Permalink to &quot;Проблемы при выращивании&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Проблема</th><th>Причина</th><th>Решение</th></tr></thead><tbody><tr><td>Пожелтение кончиков перьев</td><td>Недостаток света или слишком тесная посадка</td><td>Переставить светлее, проредить луковицы</td></tr><tr><td>Луковица гниёт</td><td>Слишком много воды, или вода застаивается</td><td>Убрать из воды, подсушить. При посадке в грунт — хороший дренаж</td></tr><tr><td>Тонкие, бледные перья</td><td>Мало света или нехватка питания</td><td>Досветка фитолампой, подкормка</td></tr><tr><td>Белый или розовый налёт на луковице</td><td>Грибковое заболевание</td><td>Луковицу выбросить, ёмкость продезинфицировать</td></tr><tr><td>Медленный рост</td><td>Холодно или старая луковица</td><td>Поставить в тепло, использовать свежие луковицы</td></tr></tbody></table><h2 id="размножение" tabindex="-1">Размножение <a class="header-anchor" href="#размножение" aria-label="Permalink to &quot;Размножение&quot;">​</a></h2><p><strong>Из луковицы (проще всего):</strong></p><ol><li>Возьмите здоровую луковицу среднего размера (лучше слегка проросшую).</li><li>Срежьте верхушку на 0.5–1 см — так перья пойдут быстрее.</li><li>Поместите луковицу в небольшой стакан с водой так, чтобы вода касалась только донца (луковица не должна плавать!).</li><li>Меняйте воду каждые 2–3 дня.</li><li>Через 7–10 дней срезайте зелень. Одна луковица даёт 2–3 урожая, затем истощается.</li></ol><p><strong>В грунте:</strong> луковицу сажают в горшок, заглубляя на 2/3. Поливают умеренно.</p><p><strong>Из семян:</strong> сейте в марте–апреле в рыхлую почву на глубину 1 см. Всходы появляются через 10–20 дней. Прореживайте, оставляя 2–3 см между растениями.</p><h2 id="как-использовать-в-еде" tabindex="-1">Как использовать в еде <a class="header-anchor" href="#как-использовать-в-еде" aria-label="Permalink to &quot;Как использовать в еде&quot;">​</a></h2><ul><li>Свежие салаты (огурцы + помидоры + лук)</li><li>Яйца с зелёным луком (глазунья, омлет, яичница-болтунья)</li><li>Зелёный лук в супы и борщи</li><li>Бутерброды с маслом и зеленью</li><li>Начинка для пирожков и блинов</li><li>Посыпка для жареной картошки</li></ul><h2 id="полезные-своиства" tabindex="-1">Полезные свойства <a class="header-anchor" href="#полезные-своиства" aria-label="Permalink to &quot;Полезные свойства&quot;">​</a></h2><ul><li>Богат витамином С (укрепляет иммунитет)</li><li>Содержит витамин А (полезен для зрения)</li><li>Фитонциды — природные антибиотики</li><li>Улучшает аппетит и пищеварение</li><li>Полезен при сезонных простудах</li></ul><h2 id="источники-информации" tabindex="-1">Источники информации <a class="header-anchor" href="#источники-информации" aria-label="Permalink to &quot;Источники информации&quot;">​</a></h2><ul><li><a href="https://ru.ruwiki.ru/wiki/%D0%9B%D1%83%D0%BA_%D1%80%D0%B5%D0%BF%D1%87%D0%B0%D1%82%D1%8B%D0%B9" target="_blank" rel="noreferrer">Лук репчатый - РуВики</a></li><li><a href="https://pogoda.mail.ru/news/59607929/" target="_blank" rel="noreferrer">Как вырастить лук на зелень на подоконнике</a></li></ul><h2 id="похожие-растения" tabindex="-1">Похожие растения <a class="header-anchor" href="#похожие-растения" aria-label="Permalink to &quot;Похожие растения&quot;">​</a></h2><ul><li><a href="/plants/microgreens.html">Микрозелень</a></li><li><a href="/plants/salad.html">Салаты</a></li><li><a href="/plants/parsley.html">Петрушка</a></li></ul>',23)])])}const b=a(i,[["render",d]]);export{p as __pageData,b as default};
